const crypto = require('crypto');

// --- 1. Парсим тело ---
let body;
try {
  const raw = $input.first().json.body;
  body = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('Invalid JSON body');
}

const initData = body.initData || '';
if (!initData) throw new Error('Missing initData');

// --- 2. HMAC-валидация initData по схеме Telegram WebApp ---
const botToken = $input.first().json.bot_token;
if (!botToken) throw new Error('TELEGRAM_BOT_TOKEN env var not set');

// Парсим initData вручную (URLSearchParams недоступен в JS Task Runner sandbox)
const pairs = initData.split('&').map(p => {
  const i = p.indexOf('=');
  return i === -1 ? [p, ''] : [decodeURIComponent(p.slice(0, i)), decodeURIComponent(p.slice(i + 1))];
});
const paramsMap = new Map(pairs);
const hash = paramsMap.get('hash');
paramsMap.delete('hash');

const dataCheckString = [...paramsMap.entries()]
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([k, v]) => `${k}=${v}`)
  .join('\n');

const secretKey = crypto.createHmac('sha256', 'WebAppData').update(botToken).digest();
const computed = crypto.createHmac('sha256', secretKey).update(dataCheckString).digest('hex');

if (computed !== hash) {
  throw new Error('Invalid initData signature');
}

// --- 3. Авторизация: дата initData не старше суток ---
const authDate = Number(paramsMap.get('auth_date')) || 0;
const nowSec = Math.floor(Date.now() / 1000);
if (nowSec - authDate > 86400) {
  throw new Error('initData too old (>24h)');
}

// --- 4. Извлекаем юзера ---
let user;
try { user = JSON.parse(paramsMap.get('user')); }
catch { throw new Error('Cannot parse user from initData'); }
if (!user || !user.id) throw new Error('No user.id in initData');

const chat_id = String(user.id);

// --- 5. Дата/время Москвы, meal_type по часу ---
const now = new Date();
// смещение Москвы +3ч; Date в n8n уже в TZ контейнера (Europe/Moscow), но подстрахуемся:
const pad = (n) => String(n).padStart(2, '0');
const date = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const time = `${pad(now.getHours())}:${pad(now.getMinutes())}`;
const h = now.getHours();
let meal_type;
if      (h < 11) meal_type = 'завтрак';
else if (h < 16) meal_type = 'обед';
else if (h < 19) meal_type = 'перекус';
else if (h < 24) meal_type = 'ужин';
else             meal_type = 'перекус';

return [{
  json: {
    chat_id,
    user_name: user.first_name || '',
    date,
    time,
    meal_type,
    payload: body,
  }
}];

// Сверяем, что строка по присланному row всё ещё та самая (защита от сдвига),
// и только тогда отдаём _row на удаление.
const v = $('Validate & Parse').first().json;
const p = v.payload || {};
const today = v.date;

const wantRow = Number(p.row);
const wantDesc = String(p.description || '');
const wantDate = (typeof p.date === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(p.date)) ? p.date : today;
if (!wantRow || wantRow < 2) throw new Error('bad_row');

const rows = $('Read Food Log').all().map((it, idx) => ({ ...it.json, _row: idx + 2 }));
const target = rows.find(r => r._row === wantRow);
if (!target) throw new Error('row_not_found_reload');
if (String(target.date) !== wantDate) throw new Error('row_date_mismatch_reload');
if (String(target.description || '') !== wantDesc) throw new Error('row_content_mismatch_reload');

return [{ json: { _row: wantRow } }];
